// Strategy shift from attempt 1.  The previous block only re-asserted the
// individual conjuncts of `next_ensures` and never touched the actual goal
// `det_..._equal(r1, r2, post1_self_@, post2_self_@, post1_netc, post2_netc)`,
// so z3 had no concrete equalities to chain.  Here we wrap the proof in
// `if H { ... }` (the postcondition is `H ==> Goal`, so the antecedent is
// only a body-level hypothesis under that guard, exactly like the
// `delegation_map::insert` worked example), then case-split on `(r1.0, r2.0)`
// and, in every reachable case, derive the four field-level conjuncts of
// `det_..._equal`:
//   (a) r1.0 == r2.0
//   (b) (r1.1)@.view() == (r2.1)@.view()     (EventResultsView)
//   (c) post1_self_@ == post2_self_@          (AbstractHostState)
//   (d) post1_netc.view() == post2_netc.view()(NetClientView)
// Each `assert` is something Verus must verify; nothing is asserted on faith.
if HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
{
    let (ok1, gres1) = r1;
    let (ok2, gres2) = r2;
    let er1: EventResults = gres1@;
    let er2: EventResults = gres2@;

    // ---- Materialise every conjunct of next_ensures for both runs ----
    assert(ok1 == post1_netc.ok());
    assert(ok2 == post2_netc.ok());
    assert(er1.well_typed_events());
    assert(er2.well_typed_events());
    assert((ok1 || er1.sends.len() > 0) ==>
        post1_netc.history() == pre_netc.history() + er1.event_seq());
    assert((ok2 || er2.sends.len() > 0) ==>
        post2_netc.history() == pre_netc.history() + er2.event_seq());

    if ok1 {
        assert(post1_self_.invariants(&post1_netc.my_end_point()));
        assert(HostState::next(pre_self_@, post1_self_@, er1.ios));
        assert(er1.event_seq() == er1.ios);
        // From `next`: constants preserved across the step.
        assert(post1_self_@.constants == pre_self_@.constants);
        // From `invariants` (now revealed): the host's `me` equals the
        // netc's end point, so the end_point side of NetClientView is
        // pinned to a function of the abstract post state.
        assert(post1_self_@.constants.me == post1_netc.my_end_point());
        // History fully determined by er1.ios.
        assert(post1_netc.history() == pre_netc.history() + er1.ios);
    }
    if ok2 {
        assert(post2_self_.invariants(&post2_netc.my_end_point()));
        assert(HostState::next(pre_self_@, post2_self_@, er2.ios));
        assert(er2.event_seq() == er2.ios);
        assert(post2_self_@.constants == pre_self_@.constants);
        assert(post2_self_@.constants.me == post2_netc.my_end_point());
        assert(post2_netc.history() == pre_netc.history() + er2.ios);
    }

    // ---- Case-split on (ok1, ok2) and derive det_..._equal field-by-field ----
    if ok1 && ok2 {
        // (a) r1.0 == r2.0 -- both are true.
        assert(ok1 == ok2);

        // (c) post_self abstract equality:
        //     post1_self_@.constants == pre_self_@.constants == post2_self_@.constants.
        //     The remaining AbstractHostState fields (delegation_map, h, sd,
        //     received_packet, num_delegations, received_requests) are pinned
        //     by the shared `next(pre_self_@, _, _)` step.
        assert(post1_self_@.constants == post2_self_@.constants);

        // (d) NetClientView equality: end_point determined by constants.me;
        //     history determined by er1.ios == er2.ios.
        assert(post1_netc.my_end_point() == post2_netc.my_end_point());
        assert(post1_netc.history() == pre_netc.history() + er1.ios);
        assert(post2_netc.history() == pre_netc.history() + er2.ios);

        // (b) EventResultsView equality: each field individually.
        //     event_seq == recvs + clocks + sends, and event_seq == ios.
        assert(er1.event_seq() == er1.recvs + er1.clocks + er1.sends);
        assert(er2.event_seq() == er2.recvs + er2.clocks + er2.sends);
    } else if !ok1 && !ok2 {
        // (a) r1.0 == r2.0 -- both are false.
        assert(ok1 == ok2);
        // No invariants/next constraints available; the schema-assume flags
        // do not pin the post states, so we can only contribute the ok
        // equality.  EventResultsView, AbstractHostState, NetClientView
        // remain z3's responsibility under any remaining triggers.
    } else {
        // (ok1, ok2) differ: r1.0 != r2.0.  det_..._equal's first conjunct
        // is already false, so the goal collapses; we still pull both
        // history/event_seq triggers in case z3 needs them downstream.
        assert(ok1 != ok2);
        assert((ok1 || er1.sends.len() > 0) ==>
            post1_netc.history() == pre_netc.history() + er1.event_seq());
        assert((ok2 || er2.sends.len() > 0) ==>
            post2_netc.history() == pre_netc.history() + er2.event_seq());
    }

    // ---- Cross-run extensionality skeleton for EventResultsView ----
    // event_seq is an open spec fn; expanding it on both runs gives the
    // EventResultsView trigger shape z3 will need to compare the two views.
    assert(er1.event_seq() == er1.recvs + er1.clocks + er1.sends);
    assert(er2.event_seq() == er2.recvs + er2.clocks + er2.sends);
}
